import { generateText } from "ai";
import { RecordId, Surreal } from "surrealdb";
import { z } from "zod";
import { ENTITY_CATEGORIES, type EntityCategory } from "../../../shared/contracts";
import { buildPmSystemPrompt } from "./prompt";
import { createPmTools } from "./tools";

const workItemSuggestionSchema = z.object({
  kind: z.enum(["task", "feature"]),
  title: z.string().min(1),
  rationale: z.string().min(1),
  category: z.enum(ENTITY_CATEGORIES).optional(),
  project: z.string().optional(),
  priority: z.string().optional(),
  possible_duplicate: z
    .object({
      id: z.string().min(1),
      name: z.string().min(1),
      similarity: z.number().min(0).max(1),
    })
    .optional(),
});

const pmAgentResultSchema = z.object({
  summary: z.string().min(1),
  suggestions: z.array(workItemSuggestionSchema),
  updated: z.array(
    z.object({
      existing_id: z.string().min(1),
      title: z.string().min(1),
      changes: z.string().min(1),
    }),
  ),
  discarded: z.array(
    z.object({
      title: z.string().min(1),
      reason: z.string().min(1),
    }),
  ),
  observations_created: z.array(z.string().min(1)),
});

export type WorkItemSuggestion = {
  kind: "task" | "feature";
  title: string;
  rationale: string;
  category?: EntityCategory;
  project?: string;
  priority?: string;
  possible_duplicate?: {
    id: string;
    name: string;
    similarity: number;
  };
};

export type PmAgentResult = {
  summary: string;
  suggestions: WorkItemSuggestion[];
  updated: Array<{ existing_id: string; title: string; changes: string }>;
  discarded: Array<{ title: string; reason: string }>;
  observations_created: string[];
};

export type PmAgentInput = {
  surreal: Surreal;
  pmModel: any;
  embeddingModel: any;
  embeddingDimension: number;
  extractionModelId: string;
  workspaceRecord: RecordId<"workspace", string>;
  conversationRecord: RecordId<"conversation", string>;
  currentMessageRecord: RecordId<"message", string>;
  latestUserText: string;
  intent: "plan_work" | "check_status" | "organize" | "track_dependencies";
  context: string;
  project?: string;
  workspaceOwnerRecord?: RecordId<"person", string>;
};

function parseJsonPayload(raw: string): unknown {
  const trimmed = raw.trim();
  if (trimmed.length === 0) {
    throw new Error("pm agent returned empty text");
  }

  try {
    return JSON.parse(trimmed);
  } catch (error) {
    throw new Error(`pm agent output is not valid strict JSON: ${error instanceof Error ? error.message : "parse error"}`);
  }
}

export async function runPmAgent(input: PmAgentInput): Promise<PmAgentResult> {
  const system = await buildPmSystemPrompt({
    surreal: input.surreal,
    workspaceRecord: input.workspaceRecord,
  });
  const intentInstruction = input.intent === "check_status"
    ? "Primary action: call get_project_status when a project scope is available."
    : input.intent === "plan_work"
      ? "Primary action: propose tasks/features with suggest_work_items, deduping each item."
      : input.intent === "track_dependencies"
        ? "Primary action: identify blockers/dependencies and create observations for high-risk paths."
        : "Primary action: organize work into clear, deduplicated next steps.";

  const result = await generateText({
    model: input.pmModel,
    system,
    prompt: [
      "You are handling a PM request.",
      `Intent: ${input.intent}`,
      input.project ? `Project hint: ${input.project}` : "Project hint: not provided",
      intentInstruction,
      "Context:",
      input.context,
      "",
      "Return strict JSON only. Do not include markdown.",
      "Schema:",
      '{"summary": string, "suggestions": WorkItemSuggestion[], "updated": Array<{"existing_id": string, "title": string, "changes": string}>, "discarded": Array<{"title": string, "reason": string}>, "observations_created": string[]}',
    ].join("\n"),
    tools: createPmTools({
      surreal: input.surreal,
      embeddingModel: input.embeddingModel,
      embeddingDimension: input.embeddingDimension,
      extractionModelId: input.extractionModelId,
    }),
    experimental_context: {
      actor: "pm_agent",
      workspaceRecord: input.workspaceRecord,
      conversationRecord: input.conversationRecord,
      currentMessageRecord: input.currentMessageRecord,
      latestUserText: input.latestUserText,
      ...(input.workspaceOwnerRecord ? { workspaceOwnerRecord: input.workspaceOwnerRecord } : {}),
    },
    maxSteps: 5,
  });

  const parsed = pmAgentResultSchema.safeParse(parseJsonPayload(result.text));
  if (!parsed.success) {
    throw new Error(`pm agent output failed validation: ${parsed.error.message}`);
  }

  return parsed.data;
}

import { RecordId, Surreal } from "surrealdb";
import { listWorkspaceProjectSummaries } from "../../graph/queries";
import { listWorkspaceOpenObservations } from "../../observation/queries";

function formatProjects(rows: Awaited<ReturnType<typeof listWorkspaceProjectSummaries>>): string {
  if (rows.length === 0) {
    return "- none";
  }

  return rows
    .slice(0, 20)
    .map((row) => `- ${row.name} [id: ${row.id}] active tasks: ${row.activeTaskCount}`)
    .join("\n");
}

function formatObservations(rows: Awaited<ReturnType<typeof listWorkspaceOpenObservations>>): string {
  if (rows.length === 0) {
    return "- none";
  }

  return rows
    .slice(0, 20)
    .map((row) => {
      const category = row.category ? `, ${row.category}` : "";
      return `- [${row.severity}] ${row.text} (${row.status}, by ${row.sourceAgent}${category})`;
    })
    .join("\n");
}

export async function buildPmSystemPrompt(input: {
  surreal: Surreal;
  workspaceRecord: RecordId<"workspace", string>;
}): Promise<string> {
  const [projects, observations] = await Promise.all([
    listWorkspaceProjectSummaries({
      surreal: input.surreal,
      workspaceRecord: input.workspaceRecord,
      limit: 20,
    }),
    listWorkspaceOpenObservations({
      surreal: input.surreal,
      workspaceRecord: input.workspaceRecord,
      limit: 20,
    }),
  ]);

  return [
    "You are the Product Manager subagent.",
    "You are the single authority on tasks, features, and project status.",
    "",
    "## Architecture: Graph as Communication Bus",
    "All agent-to-agent communication happens through the knowledge graph.",
    "Never rely on handoff text from other agents; read context from graph tools.",
    "Other agents (Research, Engineering, Marketing, etc.) write to the same graph.",
    "You may discover entities and observations created by other agents when querying.",
    "Your observations are visible to all agents in subsequent invocations.",
    "",
    "## Your Tools",
    "- search_entities: Search workspace for existing tasks, features, decisions, questions.",
    "- get_project_status: Aggregate project health (tasks, decisions, questions, blockers).",
    "- create_observation: Record risks, conflicts, or signals for other agents.",
    "- suggest_work_items: Process batches of proposed tasks/features with dedup.",
    "",
    "You may create observations directly when you detect risk, blockers, or conflicts.",
    "Do not create tasks or features directly in this workflow; return suggestions for user approval.",
    "Use tools whenever relevant data is missing.",
    "",
    "## Workspace Projects",
    formatProjects(projects),
    "",
    "## Active Observations",
    formatObservations(observations),
    "",
    "## Core Responsibilities",
    "- Task dedup and merge awareness across all agent suggestions.",
    "- Feature and dependency risk tracking (surface blockers via observations).",
    "- Project status aggregation when the user asks for status, progress, or blockers.",
    "- Cross-agent awareness: know what all agents have suggested/created.",
    "",
    "## Task Suggestion Rules",
    "1. Use suggest_work_items for every proposed task or feature.",
    "2. Exact duplicate of an open/in_progress item: treat as duplicate_found.",
    "3. Similar open/in_progress item with meaningful scope overlap: include possible_duplicate with similarity score.",
    "4. Similar closed/completed item: treat as new scope and keep as suggestion.",
    "5. No meaningful match: keep as new suggestion.",
    "",
    "## Feature Management",
    "- Features decompose into tasks. Track which tasks belong to which feature.",
    "- When all tasks for a feature are completed, note it in the summary.",
    "- Create observations when features are at risk (blocked tasks, missing tasks).",
    "",
    "## Project Status Rules",
    "- When intent is check_status, call get_project_status.",
    "- Include active tasks, blocked tasks, recent decisions, open questions, and active observations.",
    "",
    "## Observation Rules",
    "- Create observations for: cross-agent risks, conflicts, stale blockers, missing execution paths, at-risk features.",
    "- Set severity to conflict for contradictions, warning for risks, info for awareness.",
    "- Other agents will see your observations when they next query the graph.",
    "",
    "## Output",
    "Return strict JSON only (no markdown).",
    "Match this schema exactly: summary, suggestions, updated, discarded, observations_created.",
    "If no suggestions remain after dedup, return suggestions: [].",
  ].join("\n");
}

